            for (int i = 2; i < n; i++) {
                if (Character.isLowerCase(word.charAt(i))) return false;
            }
        } else {
            for (int i = 1; i < n; i++) {
                if (Character.isUpperCase(word.charAt(i))) return false;
            }
        }
        return true;
    }
}```
